 ('55000000-0000-0000-0000-000000000101','20000000-0000-0000-0000-000000000001','A1',1,$p$A Morning at Home$p$,$p$Sofía y Mateo se preparan por la mañana antes de ir a la escuela.$p$,$p$🌅$p$,$p$Es de mañana en casa de una familia. Lee y escucha qué hacen Sofía, Mateo y la abuela antes de empezar el día.$p$,60,
   $j$[{"en":"It is morning. The sun is up.","es":"Es de mañana. El sol ya salió.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000101-0.mp3"},{"en":"Sofia wakes up at seven.","es":"Sofía se despierta a las siete.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000101-1.mp3"},{"en":"Her brother Mateo is sleepy.","es":"Su hermano Mateo tiene sueño.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000101-2.mp3"},{"en":"Grandma makes coffee in the kitchen.","es":"La abuela prepara café en la cocina.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000101-3.mp3"},{"en":"The family eats bread for breakfast.","es":"La familia come pan en el desayuno.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000101-4.mp3"},{"en":"Sofia and Mateo go to school.","es":"Sofía y Mateo van a la escuela.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000101-5.mp3"},{"en":"They say goodbye to Grandma.","es":"Se despiden de la abuela.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000101-6.mp3"}]$j$::jsonb, $j$[{"word":"morning","translation":"mañana"},{"word":"wakes up","translation":"se despierta"},{"word":"sleepy","translation":"con sueño"},{"word":"kitchen","translation":"cocina"},{"word":"breakfast","translation":"desayuno"},{"word":"school","translation":"escuela"}]$j$::jsonb, $j$[{"type":"multiple_choice","skill":"reading","prompt":"¿A qué hora se despierta Sofía?","payload":{"options":["A las siete","A las nueve","A las seis"]},"correct_answer":{"value":"A las siete"},"difficulty":0.2},{"type":"multiple_choice","skill":"reading","prompt":"¿Quién prepara el café?","payload":{"options":["La abuela","Sofía","Mateo"]},"correct_answer":{"value":"La abuela"},"difficulty":0.2},{"type":"multiple_choice","skill":"reading","prompt":"¿Qué come la familia en el desayuno?","payload":{"options":["Pan","Fruta","Huevos"]},"correct_answer":{"value":"Pan"},"difficulty":0.25},{"type":"multiple_choice","skill":"reading","prompt":"¿Adónde van Sofía y Mateo?","payload":{"options":["A la escuela","Al trabajo","Al parque"]},"correct_answer":{"value":"A la escuela"},"difficulty":0.2},{"type":"cloze","skill":"reading","prompt":"Completa según la historia:","payload":{"text":"Grandma makes ___ in the kitchen."},"correct_answer":{"value":"coffee","accepted":["coffee"]},"difficulty":0.25}]$j$::jsonb),
 ('55000000-0000-0000-0000-000000000102','20000000-0000-0000-0000-000000000001','A1',2,$p$At the Market$p$,$p$Sofía compra frutas a una casera en el mercado.$p$,$p$🍎$p$,$p$Sofía va al mercado por la mañana. Compra fruta fresca a la casera.$p$,60,
   $j$[{"en":"Sofia is at the market.","es":"Sofía está en el mercado.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000102-0.mp3"},{"en":"There are many fruits here.","es":"Hay muchas frutas aquí.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000102-1.mp3"},{"en":"The mango is yellow.","es":"El mango es amarillo.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000102-2.mp3"},{"en":"I want three mangos, please.","es":"Quiero tres mangos, por favor.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000102-3.mp3"},{"en":"The seller has red apples too.","es":"La casera tiene manzanas rojas también.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000102-4.mp3"},{"en":"Three mangos cost two dollars.","es":"Tres mangos cuestan dos dólares.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000102-5.mp3"},{"en":"Sofia is happy. Thank you!","es":"Sofía está feliz. ¡Gracias!","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000102-6.mp3"}]$j$::jsonb, $j$[{"word":"market","translation":"mercado"},{"word":"fruit","translation":"fruta"},{"word":"mango","translation":"mango"},{"word":"apple","translation":"manzana"},{"word":"seller","translation":"vendedora / casera"},{"word":"dollars","translation":"dólares"}]$j$::jsonb, $j$[{"type":"multiple_choice","skill":"reading","prompt":"¿Dónde está Sofía?","payload":{"options":["In the market","In the house","In the school"]},"correct_answer":{"value":"In the market"},"difficulty":0.2},{"type":"multiple_choice","skill":"reading","prompt":"¿De qué color es el mango?","payload":{"options":["Yellow","Blue","Green"]},"correct_answer":{"value":"Yellow"},"difficulty":0.2},{"type":"multiple_choice","skill":"reading","prompt":"¿Cuántos mangos quiere Sofía?","payload":{"options":["Three","Two","Five"]},"correct_answer":{"value":"Three"},"difficulty":0.25},{"type":"multiple_choice","skill":"reading","prompt":"¿De qué color son las manzanas?","payload":{"options":["Red","Yellow","Black"]},"correct_answer":{"value":"Red"},"difficulty":0.25},{"type":"cloze","skill":"reading","prompt":"Completa según la historia:","payload":{"text":"Three mangos cost two ___."},"correct_answer":{"value":"dollars","accepted":["dollars","dollar"]},"difficulty":0.3}]$j$::jsonb),
 ('55000000-0000-0000-0000-000000000103','20000000-0000-0000-0000-000000000001','A1',3,$p$A New Friend$p$,$p$Dos chicos se conocen en la escuela y se presentan.$p$,$p$👋$p$,$p$Es el primer día de clases. Mateo, de Perú, conoce a un chico nuevo de México. Ellos se presentan.$p$,60,
   $j$[{"en":"Hi! I am Mateo.","es":"¡Hola! Soy Mateo.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000103-0.mp3"},{"en":"Hello, Mateo. I am Diego. Nice to meet you.","es":"Hola, Mateo. Soy Diego. Mucho gusto.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000103-1.mp3"},{"en":"Nice to meet you too. I am from Peru. Where are you from?","es":"Mucho gusto a ti también. Soy de Perú. ¿De dónde eres?","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000103-2.mp3"},{"en":"I am from Mexico. I am twelve years old.","es":"Soy de México. Tengo doce años.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000103-3.mp3"},{"en":"I am eleven. I like soccer. Do you like soccer?","es":"Yo tengo once. Me gusta el fútbol. ¿Te gusta el fútbol?","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000103-4.mp3"},{"en":"Yes, I like soccer too. I like music too.","es":"Sí, a mí también me gusta el fútbol. También me gusta la música.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000103-5.mp3"},{"en":"Cool! We are friends now.","es":"¡Genial! Ahora somos amigos.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000103-6.mp3"},{"en":"Yes! See you in class, Mateo.","es":"¡Sí! Nos vemos en clase, Mateo.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000103-7.mp3"}]$j$::jsonb, $j$[{"word":"friend","translation":"amigo"},{"word":"name","translation":"nombre"},{"word":"from","translation":"de (procedencia)"},{"word":"years old","translation":"años (de edad)"},{"word":"like","translation":"gustar"},{"word":"soccer","translation":"fútbol"}]$j$::jsonb, $j$[{"type":"multiple_choice","skill":"reading","prompt":"¿De dónde es Mateo?","payload":{"options":["Peru","Mexico","Brazil"]},"correct_answer":{"value":"Peru"},"difficulty":0.2},{"type":"multiple_choice","skill":"reading","prompt":"¿De dónde es Diego?","payload":{"options":["Peru","Mexico","Argentina"]},"correct_answer":{"value":"Mexico"},"difficulty":0.2},{"type":"multiple_choice","skill":"reading","prompt":"¿Cuántos años tiene Diego?","payload":{"options":["Eleven","Twelve","Ten"]},"correct_answer":{"value":"Twelve"},"difficulty":0.25},{"type":"multiple_choice","skill":"reading","prompt":"¿Qué les gusta a los dos?","payload":{"options":["Soccer","Pizza","Books"]},"correct_answer":{"value":"Soccer"},"difficulty":0.25},{"type":"cloze","skill":"reading","prompt":"Completa según la historia:","payload":{"text":"Mateo is from ___."},"correct_answer":{"value":"Peru","accepted":["Peru","peru"]},"difficulty":0.2}]$j$::jsonb),
 ('55000000-0000-0000-0000-000000000201','20000000-0000-0000-0000-000000000001','A2',1,$p$My Last Weekend$p$,$p$Carmen cuenta lo que hizo el sábado y el domingo con su familia.$p$,$p$⚽$p$,$p$Carmen vive en Lima. El fin de semana pasado visitó a su familia y vio un partido de fútbol.$p$,80,
   $j$[{"en":"Last Saturday, I visited my grandmother in the morning.","es":"El sábado pasado, visité a mi abuela en la mañana.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000201-0.mp3"},{"en":"She cooked a big lunch for all the family.","es":"Ella cocinó un gran almuerzo para toda la familia.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000201-1.mp3"},{"en":"We ate rice, chicken, and beans together.","es":"Comimos arroz, pollo y frijoles juntos.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000201-2.mp3"},{"en":"After that, my cousins and I played in the garden.","es":"Después de eso, mis primos y yo jugamos en el jardín.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000201-3.mp3"},{"en":"On Sunday, we watched a football match on TV.","es":"El domingo, vimos un partido de fútbol en la tele.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000201-4.mp3"},{"en":"Our team won the game, and we were very happy.","es":"Nuestro equipo ganó el partido, y estábamos muy felices.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000201-5.mp3"},{"en":"Then my father made coffee, but I drank juice.","es":"Luego mi papá hizo café, pero yo tomé jugo.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000201-6.mp3"},{"en":"It was a perfect weekend with my family.","es":"Fue un fin de semana perfecto con mi familia.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000201-7.mp3"}]$j$::jsonb, $j$[{"word":"visited","translation":"visité / visitó (pasado de 'visit')"},{"word":"cooked","translation":"cocinó (pasado de 'cook')"},{"word":"ate","translation":"comimos (pasado de 'eat')"},{"word":"watched","translation":"vimos / miró (pasado de 'watch')"},{"word":"won","translation":"ganó (pasado de 'win')"},{"word":"drank","translation":"tomé / bebió (pasado de 'drink')"}]$j$::jsonb, $j$[{"type":"multiple_choice","skill":"reading","prompt":"¿A quién visitó Carmen el sábado?","payload":{"options":["A su abuela","A su jefe","A un doctor"]},"correct_answer":{"value":"A su abuela"},"difficulty":0.3},{"type":"multiple_choice","skill":"reading","prompt":"¿Qué comieron juntos?","payload":{"options":["Pizza y pan","Arroz, pollo y frijoles","Solo postres"]},"correct_answer":{"value":"Arroz, pollo y frijoles"},"difficulty":0.3},{"type":"multiple_choice","skill":"reading","prompt":"¿Qué vieron el domingo?","payload":{"options":["Una película de terror","Un partido de fútbol","Las noticias"]},"correct_answer":{"value":"Un partido de fútbol"},"difficulty":0.3},{"type":"multiple_choice","skill":"reading","prompt":"¿Por qué estaban muy felices el domingo?","payload":{"options":["Porque su equipo ganó el partido","Porque perdió el otro equipo de visita","Porque empezó a llover"]},"correct_answer":{"value":"Porque su equipo ganó el partido"},"difficulty":0.45},{"type":"cloze","skill":"reading","prompt":"Completa según la historia:","payload":{"text":"On Sunday, we ___ a football match on TV."},"correct_answer":{"value":"watched","accepted":["watched"]},"difficulty":0.4}]$j$::jsonb),
 ('55000000-0000-0000-0000-000000000202','20000000-0000-0000-0000-000000000001','A2',2,$p$The Bus to the Coast$p$,$p$Lucía viaja en micro a la costa: el terminal, el boleto y el paisaje.$p$,$p$🚌$p$,$p$Lucía quería ver el mar. Tomó el micro a otra ciudad por primera vez.$p$,80,
   $j$[{"en":"Last Saturday, Lucia traveled to the coast.","es":"El sábado pasado, Lucía viajó a la costa.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000202-0.mp3"},{"en":"She arrived at the bus terminal early in the morning.","es":"Llegó al terminal de micros temprano por la mañana.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000202-1.mp3"},{"en":"She did not know the way, so she asked a man.","es":"No sabía el camino, así que le preguntó a un hombre.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000202-2.mp3"},{"en":"Where can I buy a ticket? she asked politely.","es":"¿Dónde puedo comprar un boleto?, preguntó con cortesía.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000202-3.mp3"},{"en":"The man pointed to a window near the door.","es":"El hombre señaló una ventanilla cerca de la puerta.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000202-4.mp3"},{"en":"Lucia bought a ticket and chose a window seat.","es":"Lucía compró un boleto y eligió un asiento de ventana.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000202-5.mp3"},{"en":"The bus left at nine and crossed green hills.","es":"El micro salió a las nueve y cruzó cerros verdes.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000202-6.mp3"},{"en":"There were beautiful mountains, and finally she saw the sea.","es":"Había montañas hermosas, y por fin vio el mar.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000202-7.mp3"}]$j$::jsonb, $j$[{"word":"bus terminal","translation":"terminal de micros / bus"},{"word":"ticket","translation":"boleto"},{"word":"window seat","translation":"asiento de ventana"},{"word":"the way","translation":"el camino"},{"word":"hills","translation":"cerros / colinas"},{"word":"the sea","translation":"el mar"}]$j$::jsonb, $j$[{"type":"multiple_choice","skill":"reading","prompt":"¿Adónde viajó Lucía?","payload":{"options":["A la costa","A la sierra","A la capital"]},"correct_answer":{"value":"A la costa"},"difficulty":0.3},{"type":"multiple_choice","skill":"reading","prompt":"¿Por qué le preguntó Lucía a un hombre?","payload":{"options":["Porque no sabía el camino","Porque tenía hambre","Porque perdió el boleto"]},"correct_answer":{"value":"Porque no sabía el camino"},"difficulty":0.4},{"type":"multiple_choice","skill":"reading","prompt":"¿Qué asiento eligió Lucía?","payload":{"options":["De ventana","De pasillo","Atrás del todo"]},"correct_answer":{"value":"De ventana"},"difficulty":0.35},{"type":"multiple_choice","skill":"reading","prompt":"¿Qué vio Lucía al final del viaje?","payload":{"options":["El mar","La nieve","Un río"]},"correct_answer":{"value":"El mar"},"difficulty":0.4},{"type":"cloze","skill":"reading","prompt":"Completa según la historia:","payload":{"text":"The bus left at ___ and crossed green hills."},"correct_answer":{"value":"nine","accepted":["nine"]},"difficulty":0.4}]$j$::jsonb),
 ('55000000-0000-0000-0000-000000000203','20000000-0000-0000-0000-000000000001','A2',3,$p$Maria's Birthday Party$p$,$p$Una familia prepara una fiesta de cumpleaños con piñata, torta y música.$p$,$p$🎉$p$,$p$Maria cumplió ocho años. Su familia preparó una fiesta especial en casa.$p$,80,
   $j$[{"en":"Last Saturday, Maria had a birthday party at home.","es":"El sábado pasado, Maria tuvo una fiesta de cumpleaños en casa.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000203-0.mp3"},{"en":"Her mom said: We are going to make a big cake.","es":"Su mamá dijo: Vamos a hacer una torta grande.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000203-1.mp3"},{"en":"I want a chocolate cake! Maria answered happily.","es":"¡Quiero una torta de chocolate! respondió Maria feliz.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000203-2.mp3"},{"en":"Her dad bought a colorful pinata for the children.","es":"Su papá compró una piñata colorida para los niños.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000203-3.mp3"},{"en":"Many friends and family came to the party.","es":"Muchos amigos y familiares vinieron a la fiesta.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000203-4.mp3"},{"en":"They played music and the children danced together.","es":"Pusieron música y los niños bailaron juntos.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000203-5.mp3"},{"en":"Maria opened her presents and smiled a lot.","es":"Maria abrió sus regalos y sonrió mucho.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000203-6.mp3"},{"en":"It was the best birthday party of her life.","es":"Fue la mejor fiesta de cumpleaños de su vida.","audio_url":"https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/stories/55000000-0000-0000-0000-000000000203-7.mp3"}]$j$::jsonb, $j$[{"word":"cake","translation":"torta/pastel"},{"word":"pinata","translation":"piñata"},{"word":"presents","translation":"regalos"},{"word":"party","translation":"fiesta"},{"word":"music","translation":"música"},{"word":"birthday","translation":"cumpleaños"}]$j$::jsonb, $j$[{"type":"multiple_choice","skill":"reading","prompt":"¿Qué tipo de torta quería Maria?","payload":{"options":["De chocolate","De vainilla","De fresa"]},"correct_answer":{"value":"De chocolate"},"difficulty":0.3},{"type":"multiple_choice","skill":"reading","prompt":"¿Qué compró el papá para los niños?","payload":{"options":["Una piñata","Una pelota","Una guitarra"]},"correct_answer":{"value":"Una piñata"},"difficulty":0.3},{"type":"multiple_choice","skill":"reading","prompt":"¿Cómo se sintió Maria en su fiesta?","payload":{"options":["Feliz","Triste","Aburrida"]},"correct_answer":{"value":"Feliz"},"difficulty":0.4},{"type":"multiple_choice","skill":"reading","prompt":"¿Dónde fue la fiesta de cumpleaños?","payload":{"options":["En casa","En la escuela","En el parque"]},"correct_answer":{"value":"En casa"},"difficulty":0.35},{"type":"cloze","skill":"reading","prompt":"Completa según la historia:","payload":{"text":"The children danced to the ___ at the party."},"correct_answer":{"value":"music","accepted":["music"]},"difficulty":0.4}]$j$::jsonb)
